SELECT model_name, screen_size
FROM displays
WHERE screen_size > 40;

SELECT COUNT(*) 
FROM displays 
WHERE product_line_id = 1;

SELECT change_reason, COUNT(*) AS count_of_settings
FROM settings_history
GROUP BY change_reason;

SELECT model_name, COUNT(*) AS display_count
FROM displays
GROUP BY model_name;

SELECT calibration_result, COUNT(calibration_result) AS result_count
FROM calibration_logs
GROUP BY calibration_result;
